#!/bin/bash

MODEL="litellm/glm-5.2"

echo "======================= case 1 ============================="
pi --model ${MODEL} -p "/skill:harmony-card-generation-v5 帮我创建一个父母关怀卡片，显示深圳的温度与感冒指数，并支持一键给我爸（15012345678）打电话，使用CreateMyCard技能, 生成的DSL文件保存到glm-5.2-pi目录下的单独子目录case-1下, 如需要记录布局理由、改进和校验日志，每个case子目录可保存对应的notes.md文件"

